import{o,c as i,a as t}from"./app.9d3738b3.js";const l='{"title":"@quicktvui/ai \u5F00\u53D1\u8005\u4F7F\u7528\u6307\u5357","description":"","frontmatter":{},"headers":[{"level":2,"title":"1. \u5FEB\u901F\u4E0A\u624B","slug":"_1-\u5FEB\u901F\u4E0A\u624B"},{"level":3,"title":"\u7B2C\u4E00\u6B65\uFF1A\u5B89\u88C5\u89C4\u8303\u5305","slug":"\u7B2C\u4E00\u6B65\uFF1A\u5B89\u88C5\u89C4\u8303\u5305"},{"level":3,"title":"\u7B2C\u4E8C\u6B65\uFF1A\u914D\u7F6E\u5E76\u5F00\u542F\u63A8\u8350\u6A21\u578B","slug":"\u7B2C\u4E8C\u6B65\uFF1A\u914D\u7F6E\u5E76\u5F00\u542F\u63A8\u8350\u6A21\u578B"},{"level":2,"title":"2. \u5E38\u89C1\u573A\u666F AI \u8F85\u52A9\u793A\u4F8B","slug":"_2-\u5E38\u89C1\u573A\u666F-ai-\u8F85\u52A9\u793A\u4F8B"},{"level":3,"title":"\u573A\u666F A\uFF1A\u521B\u5EFA\u65B0\u9875\u9762","slug":"\u573A\u666F-a\uFF1A\u521B\u5EFA\u65B0\u9875\u9762"},{"level":3,"title":"\u573A\u666F B\uFF1AAPI \u67E5\u8BE2","slug":"\u573A\u666F-b\uFF1Aapi-\u67E5\u8BE2"},{"level":3,"title":"\u573A\u666F C\uFF1A\u6837\u5F0F\u7EA0\u9519","slug":"\u573A\u666F-c\uFF1A\u6837\u5F0F\u7EA0\u9519"},{"level":2,"title":"3. \u5F00\u53D1\u68C0\u67E5\u6E05\u5355 (Checklist)","slug":"_3-\u5F00\u53D1\u68C0\u67E5\u6E05\u5355-checklist"},{"level":2,"title":"4. \u5982\u4F55\u4F7F\u7528 AI \u53CD\u9988\u6846\u67B6\u95EE\u9898 (Bug Reporting)","slug":"_4-\u5982\u4F55\u4F7F\u7528-ai-\u53CD\u9988\u6846\u67B6\u95EE\u9898-bug-reporting"},{"level":2,"title":"5. \u6545\u969C\u6392\u9664","slug":"_5-\u6545\u969C\u6392\u9664"}],"relativePath":"zh-CN/guide/ai/ai-assistant.md","lastUpdated":1772512045000}',a={},s=Object.assign(a,{__name:"ai-assistant",setup(d){return(c,e)=>(o(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="quicktvui-ai-\u5F00\u53D1\u8005\u4F7F\u7528\u6307\u5357" tabindex="-1">@quicktvui/ai \u5F00\u53D1\u8005\u4F7F\u7528\u6307\u5357 <a class="header-anchor vp-link" href="#quicktvui-ai-\u5F00\u53D1\u8005\u4F7F\u7528\u6307\u5357" aria-hidden="true">#</a></h1><p>\u672C\u6307\u5357\u5C06\u5E2E\u52A9\u4F60\u5229\u7528 AI \u52A9\u624B\u9AD8\u6548\u5730\u5F00\u53D1 QuickTVUI \u5E94\u7528\u3002</p><h2 id="_1-\u5FEB\u901F\u4E0A\u624B" tabindex="-1">1. \u5FEB\u901F\u4E0A\u624B <a class="header-anchor vp-link" href="#_1-\u5FEB\u901F\u4E0A\u624B" aria-hidden="true">#</a></h2><h3 id="\u7B2C\u4E00\u6B65\uFF1A\u5B89\u88C5\u89C4\u8303\u5305" tabindex="-1">\u7B2C\u4E00\u6B65\uFF1A\u5B89\u88C5\u89C4\u8303\u5305 <a class="header-anchor vp-link" href="#\u7B2C\u4E00\u6B65\uFF1A\u5B89\u88C5\u89C4\u8303\u5305" aria-hidden="true">#</a></h3><p>\u5728\u4F60\u7684 QuickTVUI \u9879\u76EE\uFF08\u5EFA\u8BAE\u4F7F\u7528 <code>quicktvui-template</code> \u521B\u5EFA\u9879\u76EE <a href="/zh-CN/guide/basic/quick-start.html" class="vp-link">\uFF08\u70B9\u51FB\u67E5\u770B\u521B\u5EFA\u9879\u76EE\uFF09</a>\uFF09\u4E2D\u5B89\u88C5\uFF1A</p><div class="language-bash"><pre><code><span class="token function">npm</span> <span class="token function">install</span> @quicktvui/ai --save-dev
</code></pre></div><h3 id="\u7B2C\u4E8C\u6B65\uFF1A\u914D\u7F6E\u5E76\u5F00\u542F\u63A8\u8350\u6A21\u578B" tabindex="-1">\u7B2C\u4E8C\u6B65\uFF1A\u914D\u7F6E\u5E76\u5F00\u542F\u63A8\u8350\u6A21\u578B <a class="header-anchor vp-link" href="#\u7B2C\u4E8C\u6B65\uFF1A\u914D\u7F6E\u5E76\u5F00\u542F\u63A8\u8350\u6A21\u578B" aria-hidden="true">#</a></h3><p>\u4E3A\u4E86\u8FBE\u5230\u6700\u4F73\u8F85\u52A9\u6548\u679C\uFF0C\u8BF7\u5728\u4F60\u7684 AI \u5DE5\u5177\u4E2D\u4F18\u5148\u9009\u62E9\u4EE5\u4E0B\u6A21\u578B\uFF1A</p><ul><li><strong>Claude</strong></li><li><strong>Codex</strong></li><li><strong>Gemini</strong></li></ul><p>AI \u52A9\u624B\u5C06\u81EA\u52A8\u8BFB\u53D6\u9879\u76EE\u6839\u76EE\u5F55\u4E0B\u7684 <code>.AGENTS.md</code>, <code>GEMINI.md</code>, <code>CLAUDE.md</code> \u7B49\u6587\u4EF6\u4E2D\u7684\u6307\u4EE4\u3002</p><h2 id="_2-\u5E38\u89C1\u573A\u666F-ai-\u8F85\u52A9\u793A\u4F8B" tabindex="-1">2. \u5E38\u89C1\u573A\u666F AI \u8F85\u52A9\u793A\u4F8B <a class="header-anchor vp-link" href="#_2-\u5E38\u89C1\u573A\u666F-ai-\u8F85\u52A9\u793A\u4F8B" aria-hidden="true">#</a></h2><h3 id="\u573A\u666F-a\uFF1A\u521B\u5EFA\u65B0\u9875\u9762" tabindex="-1">\u573A\u666F A\uFF1A\u521B\u5EFA\u65B0\u9875\u9762 <a class="header-anchor vp-link" href="#\u573A\u666F-a\uFF1A\u521B\u5EFA\u65B0\u9875\u9762" aria-hidden="true">#</a></h3><p><strong>\u8F93\u5165\uFF1A</strong> <code>\u521B\u5EFA\u4E00\u4E2A\u9875\u9762 \u9996\u9875</code><strong>AI \u5C06\u751F\u6210\uFF1A</strong> \u5305\u542B <code>onESCreate</code>, <code>onBackPressed</code>, <code>:autofocus=&quot;true&quot;</code> \u4EE5\u53CA\u6B63\u786E CSS\uFF08kebab-case + px \u5355\u4F4D\uFF09\u7684\u4EE3\u7801\u3002</p><h3 id="\u573A\u666F-b\uFF1Aapi-\u67E5\u8BE2" tabindex="-1">\u573A\u666F B\uFF1AAPI \u67E5\u8BE2 <a class="header-anchor vp-link" href="#\u573A\u666F-b\uFF1Aapi-\u67E5\u8BE2" aria-hidden="true">#</a></h3><p><strong>\u8F93\u5165\uFF1A</strong> \u201Cqt-image \u652F\u6301\u54EA\u4E9B\u5C5E\u6027\uFF1F\u201D <strong>AI \u5C06\u68C0\u7D22\uFF1A</strong> \u5B83\u4F1A\u67E5\u9605 <code>node_modules/@quicktvui/ai/rules/.docs/component/image.md</code> \u5E76\u8FD4\u56DE\uFF1A<code>src</code>, <code>enableFade</code>, <code>resizeMode</code> \u7B49\u539F\u751F\u652F\u6301\u7684\u5C5E\u6027\u3002</p><h3 id="\u573A\u666F-c\uFF1A\u6837\u5F0F\u7EA0\u9519" tabindex="-1">\u573A\u666F C\uFF1A\u6837\u5F0F\u7EA0\u9519 <a class="header-anchor vp-link" href="#\u573A\u666F-c\uFF1A\u6837\u5F0F\u7EA0\u9519" aria-hidden="true">#</a></h3><p><strong>\u8F93\u5165\uFF1A</strong> \u201C\u8FD9\u6BB5\u6837\u5F0F\u54EA\u91CC\u4E0D\u5BF9\uFF1F <code>.box { margin: 10px; width: 100%; }</code>\u201D <strong>AI \u5C06\u7EA0\u9519\uFF1A</strong> \u201C\u5728 QuickTVUI \u4E2D\u4E0D\u80FD\u4F7F\u7528 <code>margin</code> \u7B80\u5199\uFF0C\u5FC5\u987B\u62C6\u5199\u4E3A <code>margin-top</code> \u7B49\uFF1B\u4E14\u4E0D\u80FD\u4F7F\u7528 <code>100%</code>\uFF0C\u5FC5\u987B\u4F7F\u7528\u5177\u4F53\u7684 <code>px</code> \u503C\u3002\u201D</p><h2 id="_3-\u5F00\u53D1\u68C0\u67E5\u6E05\u5355-checklist" tabindex="-1">3. \u5F00\u53D1\u68C0\u67E5\u6E05\u5355 (Checklist) <a class="header-anchor vp-link" href="#_3-\u5F00\u53D1\u68C0\u67E5\u6E05\u5355-checklist" aria-hidden="true">#</a></h2><p>\u5F53 AI \u4E3A\u4F60\u751F\u6210\u4EE3\u7801\u540E\uFF0C\u8BF7\u52A1\u5FC5\u6838\u5BF9\u4EE5\u4E0B\u5173\u952E\u70B9\uFF1A</p><ul><li><strong>\u6807\u7B7E\u68C0\u67E5</strong>\uFF1A\u662F\u5426\u8BEF\u7528\u4E86 <code>p</code>, <code>img</code>, <code>h1</code>\uFF1F\uFF08\u5FC5\u987B\u662F <code>qt-text</code>, <code>qt-image</code>\uFF09</li><li><strong>\u751F\u547D\u5468\u671F</strong>\uFF1A\u5165\u53E3\u51FD\u6570\u662F\u5426\u53EB <code>onESCreate(params)</code>\uFF1F</li><li><strong>\u8FD4\u56DE\u952E</strong>\uFF1A\u5904\u7406\u51FD\u6570\u662F\u5426\u53EB <code>onBackPressed()</code> \u4E14\u5DF2 <code>return</code>\uFF1F</li><li><strong>\u7126\u70B9\u7CFB\u7EDF</strong>\uFF1A\u9875\u9762\u662F\u5426\u81F3\u5C11\u6709\u4E00\u4E2A\u5143\u7D20\u8BBE\u7F6E\u4E86 <code>:autofocus=&quot;true&quot;</code>\uFF1F</li><li><strong>\u6837\u5F0F\u5355\u4F4D</strong>\uFF1A\u662F\u5426\u6240\u6709\u6570\u503C\u90FD\u5E26 <code>px</code>\uFF1F\u662F\u5426\u8BEF\u7528\u4E86 <code>auto</code> \u6216 <code>%</code>\uFF1F</li><li><strong>\u5C5E\u6027\u547D\u540D</strong>\uFF1A<code>&lt;template&gt;</code> \u6807\u7B7E\u5C5E\u6027\u7528 <code>camelCase</code>\uFF0C<code>&lt;style&gt;</code> \u6837\u5F0F\u540D\u7528 <code>kebab-case</code>\u3002</li></ul><h2 id="_4-\u5982\u4F55\u4F7F\u7528-ai-\u53CD\u9988\u6846\u67B6\u95EE\u9898-bug-reporting" tabindex="-1">4. \u5982\u4F55\u4F7F\u7528 AI \u53CD\u9988\u6846\u67B6\u95EE\u9898 (Bug Reporting) <a class="header-anchor vp-link" href="#_4-\u5982\u4F55\u4F7F\u7528-ai-\u53CD\u9988\u6846\u67B6\u95EE\u9898-bug-reporting" aria-hidden="true">#</a></h2><p>\u5982\u679C\u4F60\u5728\u5F00\u53D1\u4E2D\u53D1\u73B0\u6846\u67B6\u53EF\u80FD\u5B58\u5728 Bug\uFF08\u4F8B\u5982 AI \u751F\u6210\u7684\u4EE3\u7801\u7B26\u5408\u89C4\u8303\u4F46\u4ECD\u8FD0\u884C\u62A5\u9519\uFF09\uFF0C\u4F60\u53EF\u4EE5\u76F4\u63A5\u901A\u8FC7 AI \u8FDB\u884C\u4E0A\u62A5\uFF1A</p><ol><li><strong>\u89E6\u53D1\u4E0A\u62A5</strong>\uFF1A\u4F60\u53EF\u4EE5\u76F4\u63A5\u5BF9 AI \u8BF4\uFF1A\u201C\u6211\u60F3\u4E0A\u62A5\u4E00\u4E2A Bug\u201D\u3001\u201C\u8FD9\u6BB5\u4EE3\u7801\u8FD0\u884C\u62A5\u9519\uFF0C\u5E2E\u6211\u53CD\u9988\u7ED9\u5B98\u65B9\u201D\u3002</li><li><strong>AI \u81EA\u52A8\u8BCA\u65AD</strong>\uFF1A</li></ol><ul><li>AI \u4F1A\u81EA\u52A8\u68C0\u6D4B\u4F60\u7684\u8FD0\u884C\u73AF\u5883\u548C\u62A5\u9519\u65E5\u5FD7\u3002</li><li>\u5B83\u4F1A\u5C1D\u8BD5\u7F16\u5199\u4E00\u4E2A<strong>\u8131\u654F\u540E\u7684\u6700\u5C0F\u53EF\u590D\u73B0 Demo</strong>\u3002</li></ul><ol start="3"><li><strong>\u5BFB\u6C42\u6388\u6743</strong>\uFF1AAI \u4F1A\u8BE2\u95EE\u4F60\uFF1A\u201C\u68C0\u6D4B\u5230\u8BE5\u95EE\u9898\u53EF\u80FD\u5C5E\u4E8E\u6846\u67B6\u7F3A\u9677\uFF0C\u662F\u5426\u5141\u8BB8\u6211\u534F\u52A9\u5C06\u5176\u4E0A\u62A5\u5230 GitHub \u5B98\u65B9\u4ED3\u5E93\uFF1F\u201D</li><li><strong>\u5FEB\u901F\u63D0\u4EA4</strong>\uFF1A\u83B7\u5F97\u6388\u6743\u540E\uFF0CAI \u4F1A\u81EA\u52A8\u5C1D\u8BD5\u5728\u4F60\u7684\u7535\u8111\u4E0A<strong>\u6253\u5F00\u6D4F\u89C8\u5668\u5E76\u9884\u586B\u5145 GitHub Issue \u5185\u5BB9</strong>\uFF0C\u4F60\u53EA\u9700\u6838\u5BF9\u540E\u70B9\u51FB\u63D0\u4EA4\u5373\u53EF\u3002</li></ol><h2 id="_5-\u6545\u969C\u6392\u9664" tabindex="-1">5. \u6545\u969C\u6392\u9664 <a class="header-anchor vp-link" href="#_5-\u6545\u969C\u6392\u9664" aria-hidden="true">#</a></h2><p>\u5982\u679C AI \u751F\u6210\u4E86\u9519\u8BEF\u7684\u4EE3\u7801\uFF08\u4F8B\u5982\u4F7F\u7528\u4E86 Web \u6807\u7B7E\uFF09\uFF1A</p><ol><li><strong>\u91CD\u65B0\u5F15\u7528\u89C4\u5219</strong>\uFF1A\u544A\u8BC9\u5B83\uFF1A\u201C\u8BF7\u53C2\u8003\u9879\u76EE\u6839\u76EE\u5F55\u4E0B\u7684 <code>AGENTS.md</code> (\u6216 <code>GEMINI.md</code> \u6216 <code>CLAUDE.md</code>) \u91CD\u65B0\u68C0\u67E5\u89C4\u8303\u3002\u201D</li><li><strong>\u5F3A\u5236\u8BFB\u53D6\u6587\u6863</strong>\uFF1A\u544A\u8BC9\u5B83\uFF1A\u201C\u8BF7\u8BFB\u53D6 <code>node_modules/@quicktvui/ai/rules/.docs/</code> \u4E0B\u7684\u76F8\u5173\u7EC4\u4EF6\u6587\u6863\u540E\u518D\u56DE\u7B54\u3002\u201D</li><li><strong>\u5F3A\u5236\u8BFB\u53D6\u6E90\u7801</strong>\uFF1A\u544A\u8BC9\u5B83\uFF1A\u201C\u8BF7\u8BFB\u53D6 <code>node_modules/@quicktvui/ai/rules/.source/</code> \u4E0B\u7684\u76F8\u5173\u6E90\u7801\u540E\u518D\u56DE\u7B54\u3002\u201D</li></ol>`,28)])]))}});export{l as __pageData,s as default};
